const monthAgo = new Date(); monthAgo.setDate(1); monthAgo.setMonth(monthAgo.getMonth()-1);
const records = $input.all().map(i=>i.json).filter(r=>r.date && new Date(r.date)>=monthAgo);
const wins = records.filter(r=>r.outcome==='win');
const losses = records.filter(r=>r.outcome==='loss');
const win_rate = records.length > 0 ? Math.round(wins.length/records.length*100) : 0;
return [{ json: { records, wins, losses, count: records.length, win_count: wins.length, loss_count: losses.length, win_rate, total_won_mrr: wins.reduce((s,r)=>s+parseFloat(r.mrr||0),0), total_lost_mrr: losses.reduce((s,r)=>s+parseFloat(r.mrr||0),0), period: new Date().toISOString().slice(0,7) } }];

