const d = $('Prepare Month Data').first().json;
let analysis;
try { analysis = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { analysis = {}; }
return [{ json: { period: d.period, count: d.count, win_rate: d.win_rate, total_won_mrr: d.total_won_mrr, total_lost_mrr: d.total_lost_mrr, generated_at: new Date().toISOString(), ...analysis } }];

